#include <bits/stdc++.h>using namespace std; #define int long long int t, n;vector<int> l;unordered_map<int, int> memo; int dp(int ind) {    if (ind >= n) return 0;        if (memo.count(ind)) return memo[ind];        int include = LLONG_MAX / 2;    if (ind + l[ind] < n) {        include = dp(ind + l[ind] + 1);    }    int exclude = dp(ind + 1) + 1;    return memo[ind] = min(include, exclude);} int32_t main() {    ios::sync_with_stdio(false);    cin.tie(NULL);        cin >> t;        for(int test = 0; test < t; test++) {        cin >> n;        l.resize(n);        for(int i = 0; i < n; i++) {            cin >> l[i];        }        memo.clear();        cout << dp(0) << "\n";    }    return 0;}